changeSet.sql:
CREATE TABLE picking ( id BIGSERIAL PRIMARY KEY,
code VARCHAR(50) NOT NULL UNIQUE,
warehouse_id BIGINT NOT NULL,
company_id BIGINT NOT NULL,
operation_type VARCHAR(30) NOT NULL, -- OUTGOING / INTERNAL / INCOMING
state VARCHAR(30) NOT NULL DEFAULT 'DRAFT', -- DRAFT / READY / IN_PROGRESS / DONE / CANCELLED
assigned_to BIGINT,
priority INTEGER DEFAULT 5,
scheduled_at TIMESTAMP, started_at TIMESTAMP, completed_at TIMESTAMP,
reference VARCHAR(100),
created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP,
CONSTRAINT chk_picking_state CHECK ( state IN ( 'DRAFT', 'READY', 'IN_PROGRESS', 'DONE', 'CANCELLED' ) ),
CONSTRAINT chk_operation_type CHECK ( operation_type IN ( 'OUTGOING', 'INTERNAL', 'INCOMING' ) ) );
CREATE INDEX idx_picking_state ON picking(state);
CREATE INDEX idx_picking_assigned ON picking(assigned_to);
CREATE INDEX idx_picking_warehouse ON picking(warehouse_id);
CREATE INDEX idx_picking_company ON picking(company_id);
CREATE INDEX idx_picking_priority ON picking(priority);
CREATE INDEX idx_picking_reference ON picking(reference);
